def predict(triples: list) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Predicates are grouped by subject to produce
    more natural phrasing and avoid repetitive subject mentions.
    """
    if not triples:
        return ""

    # Normalise input: accept Triple objects or plain (subject, predicate, object) tuples
    normalised = []
    for t in triples:
        if isinstance(t, Triple):
            subj, pred, obj = t.subject, t.predicate, t.object
        elif isinstance(t, (list, tuple)) and len(t) == 3:
            subj, pred, obj = t[0], t[1], t[2]
        else:
            # Skip malformed entries
            continue
        normalised.append((subj, pred, obj))

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present and trim whitespace."""
        return val.strip().strip('"').strip("'")

    # Mapping from subject to list of (predicate, object) pairs
    subj_map: dict[str, list[tuple[str, str]]] = {}
    for subj, pred, obj in normalised:
        subj_map.setdefault(subj, []).append((pred, _clean(obj)))

    # Helper to phrase a single predicate‑object pair
    def _phrase(s: str, p: str, o: str) -> str:
        if p == "cityServed":
            return f"{s} serves the city of {o}"
        if p == "location":
            return f"{s} is located in {o}"
        if p == "country":
            return f"{s} is in {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"{s} lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"{s} lies at an elevation of {o} feet above sea level"
        if p == "operatingOrganisation":
            return f"{s} is operated by {o}"
        if p == "runwaySurfaceType":
            return f"{s} has a runway surface of {o}"
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} metres long"
        if p == "runwayName":
            return f"{s}'s runway is named {o}"
        if p == "runwayLength":
            return f"{s}'s runway length is {o}"
        if p == "iataLocationIdentifier":
            return f"{s} has IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"{s} has ICAO code {o}"
        if p == "locationIdentifier":
            return f"{s} has location identifier {o}"
        if p == "owner":
            return f"{s} is owned by {o}"
        if p == "headquarter":
            return f"{s} has its headquarter at {o}"
        if p == "hubAirport":
            return f"{s} uses {o} as a hub airport"
        if p == "regionServed":
            return f"{s} serves the region of {o}"
        if p == "largestCity":
            return f"The largest city of {s} is {o}"
        if p == "capital":
            return f"The capital of {s} is {o}"
        if p == "language":
            return f"{s} uses {o} as its language"
        if p == "officialLanguage":
            return f"{s}'s official language is {o}"
        if p == "currency":
            return f"{s} uses the {o}"
        if p == "foundingYear":
            return f"{s} was founded in {o}"
        if p == "postalCode":
            return f"{s}'s postal code is {o}"
        if p == "areaCode":
            return f"{s}'s area code is {o}"
        if p == "ceremonialCounty":
            return f"{s} is in the ceremonial county of {o}"
        if p == "countySeat":
            return f"The county seat of {s} is {o}"
        if p == "chief":
            return f"The chief of {s} is {o}"
        # Fallback
        return f"{s} has {p} {o}"

    # Build subject‑level clauses, merging multiple predicates per subject
    # Use the subject only for the first predicate of each entity to avoid repetition.
    def _phrase_no_subject(p: str, o: str) -> str:
        """Phrase a predicate‑object pair without repeating the subject."""
        if p == "cityServed":
            return f"serves the city of {o}"
        if p == "location":
            return f"is located in {o}"
        if p == "country":
            return f"is in {o}"
        if p == "isPartOf":
            return f"is part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"lies at an elevation of {o} feet above sea level"
        if p == "operatingOrganisation":
            return f"is operated by {o}"
        if p == "runwaySurfaceType":
            return f"has a runway surface of {o}"
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            return f"{idx.lower()} runway is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            return f"{idx.lower()} runway is {o} metres long"
        if p == "runwayName":
            return f"runway is named {o}"
        if p == "runwayLength":
            return f"runway length is {o}"
        if p == "iataLocationIdentifier":
            return f"has IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"has ICAO code {o}"
        if p == "locationIdentifier":
            return f"has location identifier {o}"
        if p == "owner":
            return f"is owned by {o}"
        if p == "headquarter":
            return f"has its headquarter at {o}"
        if p == "hubAirport":
            return f"uses {o} as a hub airport"
        if p == "regionServed":
            return f"serves the region of {o}"
        if p == "largestCity":
            return f"the largest city is {o}"
        if p == "capital":
            return f"the capital is {o}"
        if p == "language":
            return f"uses {o} as its language"
        if p == "officialLanguage":
            return f"official language is {o}"
        if p == "currency":
            return f"uses the {o}"
        if p == "foundingYear":
            return f"was founded in {o}"
        if p == "postalCode":
            return f"postal code is {o}"
        if p == "areaCode":
            return f"area code is {o}"
        if p == "ceremonialCounty":
            return f"is in the ceremonial county of {o}"
        if p == "countySeat":
            return f"the county seat is {o}"
        if p == "chief":
            return f"the chief is {o}"
        # Fallback
        return f"has {p} {o}"

    subject_clauses: list[str] = []
    for s, pairs in subj_map.items():
        parts = []
        first = True
        for p, o in pairs:
            if first:
                parts.append(_phrase(s, p, o))
                first = False
            else:
                parts.append(_phrase_no_subject(p, o))
        if len(parts) == 1:
            subject_clauses.append(parts[0])
        else:
            merged = ", ".join(parts[:-1]) + ", and " + parts[-1]
            subject_clauses.append(merged)

    # Combine all subject clauses into one sentence
    if len(subject_clauses) == 1:
        sentence = subject_clauses[0] + "."
    else:
        sentence = ", ".join(subject_clauses[:-1]) + ", and " + subject_clauses[-1] + "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

